@Service
public class MfaBackupCodeService {

    @PersistenceContext
    private EntityManager entityManager;

    public void generateMfaBackupCodes(String username) {
        User user = userRepository.findByUsername(username);
        if (user != null && !user.isMfaEnabled()) {
            List<String> backupCodes = generateRandomBackupCodes(10);
            user.setMfaBackupCodes(backupCodes);
            userRepository.save(user);
        }
    }

    public boolean authenticateWithBackupCode(String username, String backupCode) {
        User user = userRepository.findByUsername(username);
        if (user != null && user.getMfaEnabled() && user.getMfaBackupCodes().contains(backupCode)) {
            return true;
        }
        return false;
    }

    private List<String> generateRandomBackupCodes(int count) {
        // implementation to generate random backup codes
        // for simplicity, we'll use a simple random number generator
        List<String> backupCodes = new ArrayList<>();
        Random random = new Random();
        for (int i = 0; i < count; i++) {
            String code = Integer.toString(random.nextInt(100000));
            backupCodes.add(code);
        }
        return backupCodes;
    }

    @Autowired
    private UserRepository userRepository;

}

@Service
public class AuthenticationProviderImpl implements AuthenticationProvider {

    @Autowired
    private MfaBackupCodeService mfaBackupCodeService;

    @Override
    public Authentication authenticate(Authentication authentication) {
        String username = authentication.getName();
        String password = (String) authentication.getCredentials();

        User user = userRepository.findByUsername(username);
        if (user != null && !user.isMfaEnabled()) {
            return new UsernamePasswordAuthenticationToken(user, password, user.getAuthorities());
        } else if (user != null && user.getMfaEnabled() && mfaBackupCodeService.authenticateWithBackupCode(username, password)) {
            return new UsernamePasswordAuthenticationToken(user, password, user.getAuthorities());
        }

        return null;
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return true;
    }
}

@Service
public class UserDetailsServiceImp implements UserDetailsService {

    @Autowired
    private UserRepository userRepository;

    @Override
    public UserDetails loadUserByUsername(String username) throws UsernameNotFoundException {
        User user = userRepository.findByUsername(username);
        if (user != null) {
            List<SimpleGrantedAuthority> authorities = new ArrayList<>();
            authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
            return new org.springframework.security.core.userdetails.User(user.getUsername(), user.getPassword(), authorities);
        }
        throw new UsernameNotFoundException("User not found");
    }
}

